            String deleteQuery = "DELETE FROM table_name WHERE condition"; // Insert SQL DELETE query here, replace 'table_name' with the actual tables names you want to operate on & insert suitable conditions in place of statement like id = 1; (replace by your real data). This is a placeholder.
            Statement stmt = conn.createStatement();   // Create MySQL DB statements — https://docs.oracle.com/javase/tutorial/jdbc/basics/index.html#statements-examples (Same as above)
